const rows = $input.first().json.rows || [];
// Compute funnel rates and deltas per page.
const thisWeek = rows.filter(r => r.dimensionValues[0]?.value && r.metricValues);
const funnel = {
  sessions: 0,
  formStarts: 0,
  formComplete: 0,
  bookings: 0,
  deposits: 0
};
thisWeek.forEach(r => {
  funnel.sessions += parseInt(r.metricValues[0].value || 0);
  funnel.formStarts += parseInt(r.metricValues[2].value || 0);
  funnel.formComplete += parseInt(r.metricValues[3].value || 0);
  funnel.bookings += parseInt(r.metricValues[4].value || 0);
  funnel.deposits += parseInt(r.metricValues[5].value || 0);
});
const rates = {
  startRate: funnel.sessions ? (funnel.formStarts / funnel.sessions * 100).toFixed(2) : 0,
  completionRate: funnel.formStarts ? (funnel.formComplete / funnel.formStarts * 100).toFixed(2) : 0,
  bookingRate: funnel.formComplete ? (funnel.bookings / funnel.formComplete * 100).toFixed(2) : 0,
  depositRate: funnel.bookings ? (funnel.deposits / funnel.bookings * 100).toFixed(2) : 0
};
return [{ json: { funnel, rates, weekEnding: new Date().toISOString().split('T')[0] } }];
